import numpy as np

def select_action(obs: np.ndarray) -> int:
    if obs[101] == 0:
        return 1

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    if not hasattr(select_action, "prev_ball_y"):
        select_action.prev_ball_y = ball_y
        select_action.prev_ball_x = ball_x
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    dy = ball_y - select_action.prev_ball_y
    dx = ball_x - select_action.prev_ball_x
    select_action.prev_ball_y = ball_y
    select_action.prev_ball_x = ball_x

    if dy < 0:
        sim_x = float(ball_x)
        sim_y = float(ball_y)
        vx = float(dx)
        vy = float(dy)
        while sim_y < 192:
            sim_y += abs(vy)
            sim_x += vx
            if sim_y > 210:
                sim_y = 210 - (sim_y - 210)
                vy = -vy
            if sim_x < 0:
                sim_x = -sim_x
                vx = -vx
            elif sim_x > 160:
                sim_x = 320 - sim_x
                vx = -vx
        target_x = int(sim_x) + 8  # constant bias offset
    else:
        target_x = ball_x

    distance = abs(target_x - paddle_x)
    if distance > 30:
        if target_x < paddle_x:
            return 3
        else:
            return 2
    elif distance > 5:
        # hysteresis: stay if already close to center
        if hasattr(select_action, "last_action") and distance < 15:
            return select_action.last_action
        if target_x < paddle_x:
            select_action.last_action = 3
            return 3
        else:
            select_action.last_action = 2
            return 2
    else:
        select_action.last_action = 0
        return 0
